solutions.cpp:
class Solution {
public:
    vector<int> reverseArray(vector<int>& nums) {
        stack<int> stack;
        for (int i = 0; i < nums.size(); ++i) {
            stack.push(nums[i]);
        }
        for (int i = nums.size() - 1; i >= 0; --i) {
            nums[i] = stack.top();
            stack.pop();
        }
        return nums;
    }
};
